import{_ as a,o,c as r,a2 as e}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"1973年 核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1973年/核心总结.md","filePath":"01_letters/1973年/核心总结.md"}'),l={name:"01_letters/1973年/核心总结.md"};function n(d,t,i,s,h,u){return o(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="_1973年-核心总结" tabindex="-1">1973年 核心总结 <a class="header-anchor" href="#_1973年-核心总结" aria-label="Permalink to &quot;1973年 核心总结&quot;">​</a></h1><blockquote><p><strong>一句话总结：</strong> ROE从19.8%回落至17.4%，保险承保利润率开始恶化。更重要的是，巴菲特开始了对华盛顿邮报的大手笔投资，伯克希尔正式从&quot;困境转型公司&quot;蜕变为&quot;长期投资平台&quot;。</p></blockquote><h2 id="核心数据" tabindex="-1">核心数据 <a class="header-anchor" href="#核心数据" aria-label="Permalink to &quot;核心数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>1973年</th><th>对比1972年</th></tr></thead><tbody><tr><td>营业收益</td><td>1193万美元</td><td>+7.3%</td></tr><tr><td>ROE</td><td><strong>17.4%</strong></td><td>-2.4个百分点</td></tr><tr><td>每股营业收益</td><td>$12.18</td><td>$11.43</td></tr><tr><td>股价涨幅</td><td>—</td><td>显著下跌</td></tr><tr><td>股票组合未实现亏损</td><td><strong>超1200万美元</strong></td><td>处境艰难</td></tr></tbody></table><h2 id="三大业务板块-两好一坏" tabindex="-1">三大业务板块：两好一坏 <a class="header-anchor" href="#三大业务板块-两好一坏" aria-label="Permalink to &quot;三大业务板块：两好一坏&quot;">​</a></h2><h3 id="银行业务-持续闪耀" tabindex="-1">银行业务：持续闪耀 <a class="header-anchor" href="#银行业务-持续闪耀" aria-label="Permalink to &quot;银行业务：持续闪耀&quot;">​</a></h3><p>Gene Abegg 继续掌舵，伊利诺伊国民银行再次创下历史新高。即便在定期存款占比超60%、需支付最高利率的情况下，税后营业收益率仍超存款规模2.1%。</p><p>银行业务已成为伯克希尔的&quot;压舱石&quot;——无论其他业务如何波动，银行始终在创造超额回报。</p><h3 id="纺织业务-价格管制的受害者" tabindex="-1">纺织业务：价格管制的受害者 <a class="header-anchor" href="#纺织业务-价格管制的受害者" aria-label="Permalink to &quot;纺织业务：价格管制的受害者&quot;">​</a></h3><p>1973年原材料价格暴涨，但美国生活成本委员会的价格管制让定价无法完全跟随成本。纺织业务的实际利润率被管制人为压低。</p><p>巴菲特在年报中直言：&quot;价格管制或许削平了行业上行期的盈利峰值，却无法避免行业下行期必然到来的利润低谷。&quot;</p><p>这说明他对纺织业务的定位非常清晰：维持但不追加投入，等待时机剥离。</p><h3 id="保险-危机前的平静" tabindex="-1">保险：危机前的平静 <a class="header-anchor" href="#保险-危机前的平静" aria-label="Permalink to &quot;保险：危机前的平静&quot;">​</a></h3><p>1973年的保险承保利润仍属良好，但多个信号已显示危机将至：</p><ul><li>大量竞争对手以低费率争抢业务</li><li>损失准备金存在普遍低估</li><li>汽车险费率无法覆盖快速上涨的通胀成本</li></ul><p>Jack Ringwalt 在这一年卸任，Phil Liesche 接任。交接顺利，理念延续。</p><h2 id="两项重大战略决策" tabindex="-1">两项重大战略决策 <a class="header-anchor" href="#两项重大战略决策" aria-label="Permalink to &quot;两项重大战略决策&quot;">​</a></h2><h3 id="_1-收购多元零售公司" tabindex="-1">① 收购多元零售公司 <a class="header-anchor" href="#_1-收购多元零售公司" aria-label="Permalink to &quot;① 收购多元零售公司&quot;">​</a></h3><p>伯克希尔与多元零售公司（Mutual Berkshire）合并，发行19.5万股伯克希尔股票（净增约8.5万股）。多元零售旗下最重要的资产是：<strong>持有蓝筹印花公司16%的股权</strong>。</p><p>这笔收购的战略意义：伯克希尔通过多元零售，间接持有蓝筹印花的少数股权，从而与蓝筹印花建立了更深的资本纽带。多年后，蓝筹印花成为伯克希尔体系内的核心控股平台。</p><h3 id="_2-大手笔增持华盛顿邮报" tabindex="-1">② 大手笔增持华盛顿邮报 <a class="header-anchor" href="#_2-大手笔增持华盛顿邮报" aria-label="Permalink to &quot;② 大手笔增持华盛顿邮报&quot;">​</a></h3><p>年报透露，巴菲特在1973年大规模增持了华盛顿邮报的股票。截至年末，持仓成本超1060万美元，持股467,150股B类股。</p><p>巴菲特写道：&quot;我们计划<strong>永久持有</strong>该笔投资。&quot;</p><p>这是伯克希尔历史上第一次明确宣布&quot;永久持有&quot;策略。</p><h2 id="关键洞察" tabindex="-1">关键洞察 <a class="header-anchor" href="#关键洞察" aria-label="Permalink to &quot;关键洞察&quot;">​</a></h2><p><strong>洞察一：未实现亏损≠投资失败</strong></p><p>1973年末，股票组合出现超1200万美元的未实现亏损。但巴菲特的判断是：按成本价计量，这些股票具备良好的投资价值，长期将带来稳健收益。</p><p>他明确区分了<strong>市场波动</strong>（不重要）与<strong>永久损失风险</strong>（重要）。这段话是后来巴菲特阐述&quot;风险&quot;定义的核心思想雏形。</p><p><strong>洞察二：ROE下降是资本扩张的必然代价</strong></p><p>巴菲特坦诚解释：股东权益规模增长速度快于收益增长，ROE必然下降。这是他有意为之的资本配置决策，不是管理失误。</p><p>提前向股东预警业绩可能下滑，并说明原因——这种坦诚沟通，成为伯克希尔年报文化的重要特征。</p><p><strong>洞察三：蓝筹印花是关键连接点</strong></p><p>1973年的这笔合并，让蓝筹印花成为伯克希尔体系的核心节点：</p><ul><li>伯克希尔 → 多元零售 → 蓝筹印花（16%）</li><li>蓝筹印花 → 喜诗糖果（1972年收购）</li></ul><p>这条资本纽带，在未来20年持续强化，最终让蓝筹印花在1983年完全并入伯克希尔体系。</p><h2 id="名言" tabindex="-1">名言 <a class="header-anchor" href="#名言" aria-label="Permalink to &quot;名言&quot;">​</a></h2><blockquote><p>&quot;我们预计，该组合长期将带来稳健的收益。&quot; ——沃伦·巴菲特，1973年年报，论股票投资组合</p></blockquote><p>（解读：&quot;长期&quot;是关键词。面对1200万美元的账面亏损，巴菲特的回应是等待——相信企业内在价值会最终反映在市场价格上。这与后来那句名言一脉相承：&quot;如果你不打算持有一只股票十年，那就不要持有十分钟。&quot;）</p><h2 id="历史坐标" tabindex="-1">历史坐标 <a class="header-anchor" href="#历史坐标" aria-label="Permalink to &quot;历史坐标&quot;">​</a></h2><ul><li>距离1956年巴菲特合伙基金：<strong>17年</strong></li><li>距离1965年接手伯克希尔：<strong>8年</strong></li><li><strong>开始大手笔投资华盛顿邮报</strong>，这笔投资最终持有40年，收益率超过百倍</li><li>距离1974年灾难性保险亏损：<strong>1年</strong></li></ul>',40)])])}const c=a(l,[["render",n]]);export{q as __pageData,c as default};
